/**
 * Notification mirrors the `notifications.notifications` row plus the
 * JSON-stringified `data` / `template_variables` payloads. Kept as
 * strings at the proto layer so the service doesn't have to enumerate
 * every possible event-data shape — the gateway parses them back to
 * JSON when translating to REST.
 */
export interface Notification {
  notificationId: string;
  userId: string;
  type: NotificationType;
  channel: NotificationChannel;
  priority: NotificationPriority;
  status: NotificationStatus;
  title: string;
  message: string;
  dataJson: string;
  templateId?: string | undefined;
  templateVariablesJson: string;
  relatedEntityType?: NotificationRelatedEntityType | undefined;
  relatedEntityId?: string | undefined;
  /**
   * RFC 3339 timestamps — `optional` markers mirror the table's
   * NULL columns. created_at / updated_at are never null.
   */
  scheduledFor?: string | undefined;
  sentAt?: string | undefined;
  deliveredAt?: string | undefined;
  readAt?: string | undefined;
  clickedAt?: string | undefined;
  expiresAt?: string | undefined;
  retryCount: number;
  maxRetries: number;
  errorMessage?: string | undefined;
  externalId?: string | undefined;
  createdAt: string;
  updatedAt: string;
}

export interface CreateNotificationRequest {
  /**
   * Target user — the principal calling Create is typically a service
   * (notifications.create permission), not the recipient.
   */
  userId: string;
  type: NotificationType;
  channel: NotificationChannel;
  /** Defaults to NOTIFICATION_PRIORITY_NORMAL when UNSPECIFIED. */
  priority: NotificationPriority;
  title: string;
  message: string;
  /** JSON-stringified opaque payload. Empty string == `{}`. */
  dataJson: string;
  templateId?: string | undefined;
  templateVariablesJson: string;
  relatedEntityType?: NotificationRelatedEntityType | undefined;
  relatedEntityId?: string | undefined;
  scheduledFor?: string | undefined;
  expiresAt?: string | undefined;
  /**
   * External tracking id (e.g. SendGrid message id). Optional at create
   * time; the email/SMS workers stamp it later when they ship the message.
   */
  externalId?: string | undefined;
}

export interface CreateNotificationResponse {
  notification?: Notification | undefined;
}

export interface ListNotificationsRequest {
  /**
   * Opaque base64-JSON keyset cursor — same shape CAD uses for the
   * audit query. Callers pass the previous response's next_cursor
   * back here; the format is the service's private concern.
   */
  cursor?: string | undefined;
  /**
   * Defaults to 20, max 100 — server enforces the bound, returns
   * INVALID_ARGUMENT on overflow.
   */
  limit: number;
  /**
   * Optional filters. UNSPECIFIED in the enum = "no filter on this
   * field" — same convention every notification ENUM in this file uses.
   */
  statusFilter: NotificationStatus;
  channelFilter: NotificationChannel;
  typeFilter: NotificationType;
}

export interface ListNotificationsResponse {
  notifications: Notification[];
  /**
   * Absent when the result set is exhausted. Same string a future
   * ListNotificationsRequest.cursor would carry.
   */
  nextCursor?: string | undefined;
}

export interface DismissNotificationRequest {
  notificationId: string;
}

export interface DismissNotificationResponse {
  /**
   * The updated row (status=READ, read_at=now). Idempotent: a second
   * Dismiss on the same notification_id returns the same payload.
   */
  notification?: Notification | undefined;
}

export interface SendEmailRequest {
  /** Recipient. Required. */
  toEmail: string;
  toName?: string | undefined;
  /** Sender override (defaults to the service's configured From). */
  fromEmail?: string | undefined;
  fromName?: string | undefined;
  replyToEmail?: string | undefined;
  /** CC / BCC. Empty when omitted. */
  ccEmails: string[];
  bccEmails: string[];
  /**
   * Either supply (subject + html_content) OR (template_id + template_data_json).
   * When both arrive, template wins and the inline subject/content are ignored.
   */
  subject?: string | undefined;
  htmlContent?: string | undefined;
  textContent?: string | undefined;
  templateId?: string | undefined;
  /**
   * JSON-stringified payload for template variable substitution.
   * Empty string == `{}`.
   */
  templateDataJson: string;
  type: EmailType;
  priority: EmailPriority;
  /**
   * Schedule for a future delivery. Absent = send as soon as the worker
   * picks it up.
   */
  scheduledFor?: string | undefined;
  /** Free-form metadata + tags for the row. JSON-stringified; empty string == `{}`. */
  metadataJson: string;
  tags: string[];
  /** Tie the row to a user (for prefs enforcement + audit). Optional. */
  userId?: string | undefined;
  campaignId?: string | undefined;
  /**
   * Opt-in idempotency. When set, a duplicate SendEmail with the same
   * key returns the same email_id without enqueueing a second row.
   */
  idempotencyKey?: string | undefined;
}

export interface SendEmailResponse {
  /**
   * The row's emailId. Caller can poll the queue table for status; the
   * worker publishes status changes on `notifications.email.*` topics.
   */
  emailId: string;
  /** True when the row was already present (idempotency_key collision). */
  alreadyQueued: boolean;
}

